INSERT INTO `shop` VALUES (1, './images/mysqlimg/LONGINESlogo.jpg', './images/mysqlimg/LONGINESimg.jpg', '浪琴LONGINES', '绅士专区', '名媛专区', '功能分类', '　　浪琴Longines手表自1832年在瑞士索伊米亚(Saint-Imier)创立开始，在全球屡屡突破制表技术而傲视同行，同时又不失体现其优雅风范。1912年，浪琴手表在世界运动会中缔造了历史性时刻率先运用断线远离，于比赛场上的起点与终点分别启动及终止计时装置。浪琴手表自此成为多项国际赛事的制定官方计时器，包括多次冬季与夏季奥运会。浪琴手表与航空及航海历史接下不解之缘。譬如浪琴手表为飞行家连拔(Lindbergh)首次个人横越大西洋计算飞行时间，期后更依照连拔的设计制造了Hour angle导航腕表。', '浪琴LONGINES', '61135', '75258', './images/mysqlimg/LONGINESsign.jpg', './images/mysqlimg/LONGINEScontentimg1.jpg', './images/mysqlimg/LONGINEScontentimg2.jpg', './images/mysqlimg/LONGINEScontentimg3.jpg', './images/mysqlimg/LONGINEScontentimg4.jpg', './images/mysqlimg/LONGINEScontentimg5.jpg', './images/mysqlimg/LONGINEScontentimg6.jpg', './images/mysqlimg/LONGINEScontentimg7.jpg', './images/mysqlimg/LONGINEScontentimg15.jpg', './images/mysqlimg/LONGINESgoods1.jpg', '7,940', '720', '8640', '浪琴Longines-康卡斯系列 L3.742.4.96.6  自动机械男表', './images/mysqlimg/LONGINESgoods2.jpg', '7,899', '717', '8599', '浪琴Longines-康卡斯系列 L3.741.4.56.6 机械男表', './images/mysqlimg/LONGINESgoods3.jpg', '10,200', '942', '11300', '浪琴Longines-心月系列 L8.111.4.71.6  机械女表', './images/mysqlimg/LONGINESgoods4.jpg', '8,390', '756', '9090', '浪琴longies-瑰丽系列 L4.921.4.11.6 机械男表', './images/mysqlimg/LONGINESgoods5.jpg', '6,700', '623', '7470', '浪琴Longines-嘉岚系列 L4.209.4.11.6 石英女表', './images/mysqlimg/LONGINESgoods6.jpg', '12,760', '1155', '13860', '浪琴Longines-名匠系列 L2.628.4.78.6 机械男表', './images/mysqlimg/LONGINESgoods7.jpg', '8,390', '756', '9090', '浪琴longines-瑰丽系列 L4.921.4.12.6 机械男表 ', './images/mysqlimg/LONGINESgoods8.jpg', '9,000', '750', '9000', '浪琴Longines-瑰丽系列 L4.321.2.11.7 机械女表');
INSERT INTO `shop` VALUES (2, './images/mysqlimg/ROLEXlogo.jpg', './images/mysqlimg/ROLEXimg.jpg', '劳力士ROLEX', '男士腕表', '女士腕表', '人群', '劳力士Rolex的发展史与它的创始人汉斯·威尔斯多夫(Hans Wilsdorf)的名字紧密相联。1881年出生在巴伐利亚一座城市里，他年轻时就涉足国际商业。开始时作养殖珍珠的生意，19岁居瑞士拉夏德芬(La Chaux-de-Fonds)，为一家专门出口的钟表制造厂作代理。1905年，他创办了自己的企业，名为“威尔斯多夫及戴维公司”(Wilsdorf and Davis)，是一家主要负责销售手表的公司，但他也研发自制手表。', '劳力士ROLEX', '1197', '24149', './images/mysqlimg/ROLEXsign.jpg', './images/mysqlimg/ROLEXcontentimg1.jpg', './images/mysqlimg/ROLEXcontentimg2.jpg', './images/mysqlimg/ROLEXcontentimg3.jpg', './images/mysqlimg/ROLEXcontentimg4.jpg', './images/mysqlimg/ROLEXcontentimg5.jpg', './images/mysqlimg/ROLEXcontentimg6.jpg', './images/mysqlimg/ROLEXcontentimg7.jpg', './images/mysqlimg/ROLEXcontentimg8.jpg', './images/mysqlimg/ROLEXgoods1.jpg', '48510', '4043', '48510', '劳力士-空中霸王系列 114234-70190蓝色橙色阿拉伯数字 男士自动机械表', './images/mysqlimg/ROLEXgoods2.jpg', '72800', '6067', '72800', '劳力士ROLEX-空中霸王系列 116900-71200黑色369阿拉伯数字 机械男表', './images/mysqlimg/ROLEXgoods3.jpg', '48510', '4043', '48510', '劳力士-空中霸王系列 114234-70190粉红色369阿拉伯数字 男士自动机械表', './images/mysqlimg/ROLEXgoods4.jpg', '64200', '5350', '64200', '劳力士-空中霸王系列 114234-70190粉红色罗马数字11钻 中性自动机械表', './images/mysqlimg/ROLEXgoods5.jpg', '101230', '8435', '101230', '劳力士ROLEX-蚝式恒动系列 116231-63201黑色纪念花纹10钻 机械男表', './images/mysqlimg/ROLEXgoods6.jpg', '118700', '9892', '118700', '劳力士ROLEX-日志型系列 126333-G-62613黄石 机械男表', './images/mysqlimg/ROLEXgoods7.jpg', '44000', '3666', '44000', '劳力士Rolex-蚝式恒动系列 116000-70200WT 自动机械男表', './images/mysqlimg/ROLEXgoods8.png', '41000', '3417', '41000', '劳力士ROLEX-蚝式恒动系列 177200-70160蓝罗 自动机械女表');
INSERT INTO `shop` VALUES (3, './images/mysqlimg/eposlogo.jpg', './images/mysqlimg/eposimg.jpg', '瑞士爱宝时官方旗舰店', '商务', '休闲', '运动', '　　瑞士品牌爱宝时Epos起源要追溯到1925年。在当年，詹姆斯‧欧伯特(James Aubert) 在瑞士侏罗山区成立他的机械机芯制表公司。侏罗山区被称为世界机械腕表中心，这里聚集着众多的腕表技术、艺术大师;几个世纪以来，瑞士侏罗山区已经享誉世界。', '瑞士爱宝时官方旗舰店', '65407', '30211', './images/mysqlimg/epossign.jpg', './images/mysqlimg/eposcontentimg1.jpg', './images/mysqlimg/eposcontentimg2.jpg', './images/mysqlimg/eposcontentimg3.jpg', './images/mysqlimg/eposcontentimg4.jpg', './images/mysqlimg/eposcontentimg5.jpg', './images/mysqlimg/eposcontentimg6.jpg', './images/mysqlimg/eposcontentimg7.jpg', './images/mysqlimg/eposcontentimg8.jpg', './images/mysqlimg/eposgoods1.jpg', '7,100', '666', '8000', '瑞士艺术制表大师爱宝时（EPOS）-Emotion情感系列 日夜无间 3390.302.20.38.25 机械男表', './images/mysqlimg/eposgoods2.jpg', '6,300', '640', '7680', '瑞士艺术制表大师爱宝时（EPOS）-Emotion情感系列 经典罗马假期-白 3390.152.20.20.25 机械男表', './images/mysqlimg/eposgoods3.jpg', '6,260', '580', '6960', '瑞士艺术制表大师爱宝时（EPOS）-Ladies女士系列 心跳时光 4314.133.20.50.10 机械女表', './images/mysqlimg/eposgoods4.jpg', '10,860', '1013', '12160', '瑞士艺术制表大师爱宝时（EPOS）-Emotion情感系列 追逐巨擘-白 3390.155.20.20.25 机械男表', './images/mysqlimg/eposgoods5.jpg', '10,240', '1046', '12560', '瑞士艺术制表大师爱宝时（EPOS）-Emotion情感系列 追逐巨擘 3390.156.22.25.25 机械男表', './images/mysqlimg/eposgoods6.jpg', '7,120', '660', '7920', '瑞士艺术制表大师爱宝时（EPOS）-Sportive运动系列 海兽克拉肯 3441.131.96.56.30 机械男表', './images/mysqlimg/eposgoods7.jpg', '8,600', '800', '9600', '【预售】瑞士艺术制表大师爱宝时（EPOS）-Passion激情系列 3434.183.20.38.25 收藏家机械男表 限', './images/mysqlimg/eposgoods8.jpg', '5,580', '523', '6280', '瑞士艺术制表大师爱宝时（EPOS）-Emotion情感系列 罗马假期-水蓝版 3390.152.20.16.25 机械男表');
INSERT INTO `shop` VALUES (4, './images/mysqlimg/OMEGAlogo.jpg', './images/mysqlimg/OMEGAimg.jpg', '欧米茄', '正装', '运动', '休闲', '1848年，瑞士联邦诞生，路易·勃兰特(Louis Brandt)与拉夏德芬(La Chaux-de-Fonds)开始手表装嵌工作。1880年，路易·勃兰特的儿子Louis-Paul及Csar将厂房搬迁至人力充足、资源丰富且交通方便的比尔(Bienne)地区。此后，采用机械化生产，统一规格零件，并引进新式分工系统进行装配工作，装制出精密准确、品质优良且价格合理的表款。', '欧米茄OMEGA', '34715', '76711', './images/mysqlimg/OMEGAsign.jpg', './images/mysqlimg/OMEGAcontentimg1.jpg', './images/mysqlimg/OMEGAcontentimg2.jpg', './images/mysqlimg/OMEGAcontentimg3.jpg', './images/mysqlimg/OMEGAcontentimg4.jpg', './images/mysqlimg/OMEGAcontentimg5.jpg', './images/mysqlimg/OMEGAcontentimg6.jpg', './images/mysqlimg/OMEGAcontentimg7.jpg', './images/mysqlimg/OMEGAcontentimg8.jpg', './images/mysqlimg/OMEGAgoods1.jpg', '23,600', '2016', '24200', '欧米茄Omega-碟飞系列 424.13.40.20.01.001 机械男表', './images/mysqlimg/OMEGAgoods2.jpg', '124,420', '10710', '128520', '欧米茄 Omega-星座系列 131.53.39.20.02.002 自动机械男表', './images/mysqlimg/OMEGAgoods3.jpg', '18,400', '1533', '18400', '欧米茄 Omega-星座系列曼哈顿腕表 131.10.28.60.06.001 石英女表', './images/mysqlimg/OMEGAgoods4.jpg', '49,000', '4216', '50600', '欧米茄Omega-海马系列300米潜水表 210.30.44.51.03.001 自动机械男表', './images/mysqlimg/OMEGAgoods5.jpg', '35,684', '3065', '36784', '欧米茄Omega-海马系列 AQUA TERRA 150米腕表220.13.41.21.03.003 自动机械男表', './images/mysqlimg/OMEGAgoods6.jpg', '55,200', '4600', '55200', '欧米茄Omega-海马系列300米潜水表 210.92.44.20.01.001 自动机械男表', './images/mysqlimg/OMEGAgoods7.jpg', '66,700', '5558', '66700', '欧米茄OMEGA-超霸系列 304.33.44.52.03.001 机械男表', './images/mysqlimg/OMEGAgoods8.jpg', '42,900', '3666', '44000', '欧米茄OMEGA-海马系列 215.30.44.21.01.002 机械男表');
INSERT INTO `shop` VALUES (5, './images/mysqlimg/ruishilogo.jpg', './images/mysqlimg/ruishiimg.jpg', '瑞士库尔沃官方旗舰店', '绅士专区', '名媛专区', '风格', '　　Cuervo y Sobrinos(中文名：库尔沃)：一个起源于南美洲，发展于瑞士的古老品牌，拥有130年的悠久历史。诞生在被誉为“加勒比海明珠”的古巴哈瓦那，这里曾是拉丁美洲最繁华的都市，一度以奢华、顶端的艺术品而享誉全球。目前公司总部设在瑞士卢加诺附近的卡帕拉古---拥有浓厚制表文化的瑞士小镇，所有的CYS品牌腕表都在这里精心制作，每年只为全球客户提供3000只作品。CYS品牌腕表的设计品味展现出浓厚的拉丁风情，加上每个系列的名字均来源于古巴著名的雪茄，让每只CYS腕表充满了十九世纪末哈瓦那的迷人气息。', '瑞士库尔沃官方旗舰店', '26241', '72454', './images/mysqlimg/CYSsign.jpg', './images/mysqlimg/CYScontentimg1.jpg', './images/mysqlimg/CYScontentimg2.jpg', './images/mysqlimg/CYScontentimg3.jpg', './images/mysqlimg/CYScontentimg4.jpg', './images/mysqlimg/CYScontentimg5.jpg', './images/mysqlimg/CYScontentimg6.jpg', './images/mysqlimg/CYScontentimg7.jpg', './images/mysqlimg/CYScontentimg8.jpg', './images/mysqlimg/CYSgoods1.jpg', '16,660', '1546', '18560', '【商务简约款】瑞士库尔沃CYS-Historiador 历史学家系列 pequenos segundos 3195.1CS.AR 机械男表', './images/mysqlimg/CYSgoods2.jpg', '18,560', '1546', '18560', '拥有拉丁血统的瑞士腕表品牌：瑞士库尔沃CYS-Historiador 历史学家系列 pequenos segundos 3195B.1CS.', './images/mysqlimg/CYSgoods3.jpg', '20,100', '1866', '22400', '瑞士库尔沃CYS-Historiador 历史学家系列 3195.1TR.C', './images/mysqlimg/CYSgoods4.jpg', '16,660', '1546', '18560', '【预售】库尔沃火焰纹款 拥有拉丁血统的瑞士腕表品牌：瑞士库尔沃CYS-Historiador 历史学家', './images/mysqlimg/CYSgoods5.jpg', '16,660', '1546', '18560', '【预售】库尔沃火焰纹款 拥有拉丁血统的瑞士腕表品牌：瑞士库尔沃CYS-Historiador 历史学家', './images/mysqlimg/CYSgoods6.jpg', '16,660', '1546', '18560', '【蓝色妖姬】拥有拉丁血统的瑞士腕表品牌：瑞士库尔沃CYS-Historiador 历史学家系列 pequenos s', './images/mysqlimg/CYSgoods7.jpg', '16,660', '1546', '18560', '包豪斯工艺美学款 拥有拉丁血统的瑞士腕表品牌：瑞士库尔沃CYS-Historiador 历史学家系列 包', './images/mysqlimg/CYSgoods8.jpg', '16,660', '1546', '18560', '包豪斯工艺美学款 拥有拉丁血统的瑞士腕表品牌：瑞士库尔沃CYS-Historiador 历史学家系列 包');
INSERT INTO `shop` VALUES (6, './images/mysqlimg/MIDOlogo.jpg', './images/mysqlimg/MIDOimg.jpg', '美度MIDO', '男女表', '表款系列', '风格分类', '美度表由George Schaeren于1918年在瑞士苏黎士创立。今天美度表公司总部坐落于瑞士Jura山脉中心的勒克勒尔(Le Locle)小镇。美度表的名字源于西班牙语“Yo mido”,意为“我衡量”。它意在制造一块能成为你亲密朋友的手表，当你看着美度表时心情愉快，在你需要时，它会伴你左右，美度是一块非常值得信赖腕表。美度表——一块富有个性与你相依一生的瑞士表。', '美度MIDO', '47968', '43545', './images/mysqlimg/MIDOsign.jpg', './images/mysqlimg/MIDOcontentimg1.jpg', './images/mysqlimg/MIDOcontentimg2.jpg', './images/mysqlimg/MIDOcontentimg3.jpg', './images/mysqlimg/MIDOcontentimg4.jpg', './images/mysqlimg/MIDOcontentimg5.jpg', './images/mysqlimg/MIDOcontentimg6.jpg', './images/mysqlimg/MIDOcontentimg7.jpg', './images/mysqlimg/MIDOcontentimg8.jpg', './images/mysqlimg/MIDOgoods1.jpg', '4,310', '396', '4760', '美度MIDO-贝伦赛丽系列 M8600.4.26.8 机械男表', './images/mysqlimg/MIDOgoods2.jpg', '4,600', '425', '5100', '美度MIDO-贝伦赛丽系列 M8600.4.18.1 机械男表', './images/mysqlimg/MIDOgoods3.jpg', '4,770', '439', '5270', '美度MIDO-贝伦赛丽系列 M8600.3.13.4 机械男表', './images/mysqlimg/MIDOgoods4.jpg', '6,150', '566', '6800', '美度MIDO-舵手MULTIFORT系列 M005.430.36.051.80 机械男表（随表附送一条橙色表带）', './images/mysqlimg/MIDOgoods5.jpg', '4,600', '425', '5100', '美度MIDO-贝伦赛丽系列 M7600.4.26.1 机械女表', './images/mysqlimg/MIDOgoods6.jpg', '5,605', '517', '6205', '美度-贝伦赛丽系列 M007.207.36.036.00 机械女表', './images/mysqlimg/MIDOgoods7.jpg', '4,770', '439', '5270', '美度MIDO-贝伦赛丽系列 M7600.3.26.8 机械女表', './images/mysqlimg/MIDOgoods8.jpg', '6,525', '602', '7225', '美度MIDO-贝伦赛丽 BARONCELLI系列 M027.207.36.260.00 机械女表');
INSERT INTO `shop` VALUES (7, './images/mysqlimg/HERBELINlogo.jpg', './images/mysqlimg/HERBELINimg.jpg', '法国赫柏林官方旗舰店', '男表', '男表专区', '风格', '赫柏林Michel Herbelin，创立于1947年法瑞交界处有“世界奢侈钟表制造中心”美誉之称的汝拉区沙尔克蒙，至今已有70余年制表历史。浪漫的风格、独特的设计、细腻的做工、上乘的质量，是赫柏林(Herbelin)的产品特色。自诞生起，赫柏林已生产超过1000万枚手表，以优雅的风格传承法国的奢侈品精神，并常年保持在法30%的市场份额，是法国著名的时尚优雅腕表品牌。', '法国赫柏林官方旗舰店', '125733', '45298', './images/mysqlimg/HERBELINsign.jpg', './images/mysqlimg/HERBELINcontentimg1.jpg', './images/mysqlimg/HERBELINcontentimg2.jpg', './images/mysqlimg/HERBELINcontentimg3.jpg', './images/mysqlimg/HERBELINcontentimg4.jpg', './images/mysqlimg/HERBELINcontentimg5.jpg', './images/mysqlimg/HERBELINcontentimg6.jpg', './images/mysqlimg/HERBELINcontentimg7.jpg', './images/mysqlimg/HERBELINcontentimg8.jpg', './images/mysqlimg/HERBELINgoods1.jpg', '3,400', '316', '3800', '【预计4月底发货】法国优雅时尚腕表品牌：Michel Herbelin赫柏林  Perles珍珠系列  珍珠恋人  16', './images/mysqlimg/HERBELINgoods2.jpg', '3,900', '366', '4400', '【明星同款】法国优雅时尚腕表品牌：Michel Herbelin赫柏林 Antarès恒星系列  吉普赛女郎  COF.1', './images/mysqlimg/HERBELINgoods3.jpg', '1,860', '180', '2160', '法国国民腕表品牌：Michel Herbelin赫柏林  City都市系列  蓝色星空  19515/15  男士石英表', './images/mysqlimg/HERBELINgoods4.jpg', '4,499', '416', '4999', '法国国民腕表品牌：Michel Herbelin赫柏林-City都市系列-雅士 1669/07GO.FR 男士自动机械表', './images/mysqlimg/HERBELINgoods5.jpg', '5,780', '540', '6480', '法国优雅时尚腕表品牌：Michel Herbelin赫柏林-Metropole大都会系列-诺曼底公爵 1643/08.FR 男士自', './images/mysqlimg/HERBELINgoods6.jpg', '5,400', '508', '6100', '法国国民腕表品牌：赫柏林Michel Herbelin   Capcamarat 蔚蓝海岸系列   1645/B15  鹦鹉螺 男士机械', './images/mysqlimg/HERBELINgoods7.jpg', '1,860', '180', '2160', '法国国民腕表品牌：Michel Herbelin赫柏林  Classiques经典系列  永恒绅士  12443/S01  男士石英表', './images/mysqlimg/HERBELINgoods8.jpg', '5,099', '474', '5699', '法国国民腕表品牌：赫柏林Michel Herbelin Trophy 领航员系列 1660/22TER 极地迷棕 男士机械表');
INSERT INTO `shop` VALUES (8, './images/mysqlimg/DAVOSAlogo.jpg', './images/mysqlimg/DAVOSAimg.jpg', '瑞士迪沃斯官方旗舰店', '人群划分', '功能选择', '搭配风格', '　　迪沃斯在1861年创立于瑞士制表工艺重镇--侏罗山区。迪沃斯坚持以无懈可击的质量、创新的材料、精密的机械展现品牌独具的现代风格和个性奢华。它采用的所有机芯全部源自于自身创意，对古董机芯进行重新研发并创造出别具特色的迪沃斯机芯。迪沃斯以研发高品质的男士机械表为主，在设计上追求功能强大、外观沉稳大气。而女士腕表精致婉约，是现代女性完美的饰品。迪沃斯适合追求不俗生活品味，对机械表情有独钟的你。在瑞士腕表行列中，迪沃斯坚持以实在的价格和高级腕表的完美品质，满足更多消费者的个性需求，做“你能拥有的奢华”机械表。', '瑞士迪沃斯官方旗舰店', '108770', '96615', './images/mysqlimg/DAVOSAsign.jpg', './images/mysqlimg/DAVOSAcontentimg1.jpg', './images/mysqlimg/DAVOSAcontentimg2.jpg', './images/mysqlimg/DAVOSAcontentimg3.jpg', './images/mysqlimg/DAVOSAcontentimg4.jpg', './images/mysqlimg/DAVOSAcontentimg5.jpg', './images/mysqlimg/DAVOSAcontentimg6.jpg', './images/mysqlimg/DAVOSAcontentimg7.jpg', './images/mysqlimg/DAVOSAcontentimg8.jpg', './images/mysqlimg/DAVOSAgoods1.jpg', '1,860', '180', '2160', '纯正瑞士品牌 迪沃斯DAVOSA-Executive行政系列 Classic经典石英 30mm 黑盘精钢 16858755 女士商务休', './images/mysqlimg/DAVOSAgoods2.jpg', '1,480', '140', '1680', '瑞士进口 迪沃斯（DAVOSA）- Classic Quartz 经典系列 16755655 石英女表（已绝版）', './images/mysqlimg/DAVOSAgoods3.jpg', '2,500', '233', '2800', '纯正瑞士品牌 迪沃斯DAVOSA-Executive行政系列 Vireo Chrono 商务精英 计时版 白盘全钢 41mm 16348115 ', './images/mysqlimg/DAVOSAgoods4.jpg', '1,840', '153', '1840', '纯正瑞士品牌 迪沃斯DAVOSA-Executive行政系列 Parangon 现代模范 白 16756315 女士商务休闲石英表', './images/mysqlimg/DAVOSAgoods5.jpg', '1,860', '180', '2160', '纯正瑞士品牌 迪沃斯DAVOSA-Pilot 领航系列 Aviator飞行员 16249845 男士商务休闲石英表', './images/mysqlimg/DAVOSAgoods6.jpg', '1,990', '190', '2290', '纯正瑞士品牌 迪沃斯DAVOSA-Diving 潜水系列 VintageDiver 复古潜水员 16250045 男士商务休闲石英表', './images/mysqlimg/DAVOSAgoods7.jpg', '2,500', '233', '2800', '纯正瑞士品牌 迪沃斯DAVOSA-Diving 潜水系列 VintageDiver 复古潜水员 16350060 男士商务休闲石英表', './images/mysqlimg/DAVOSAgoods8.jpg', '2,880', '240', '2880', '纯正瑞士品牌 迪沃斯DAVOSA-Pilot 领航系列 AviatorFlyback 飞返计时飞行员 16249915 男士商务休闲');
INSERT INTO `shop` VALUES (9, './images/mysqlimg/paulpicollogo.jpg', './images/mysqlimg/paulpicolimg.jpg', '瑞士柏高官方旗舰店', '系列分类', '男士腕表', '女士腕表', '瑞士柏高（Paul Picot）制表公司在1976年诞生于瑞士制表圣地汝拉山谷（Jura）的勒努瓦尔蒙（Le Noirmont）。70年代，在瑞士机械表受到日本石英技术严重冲击的情况下，瑞士柏高品牌创始人马里奥，始终坚信机械表仍会是市场的宠儿，将创新技术与瑞士制表传统完美地结合起来。秉承对细节的倾注，柏高采用欧洲顶级的工厂打造黄金表壳，对走时要求极高，制造出通过天文台认证的高质量腕表。柏高的制表师掌握了三问、陀飞轮、万年历、珐琅等高超制表工艺与技术，擅长制造优雅的复杂功能腕表，产品别具匠心还蕴藏珍稀的超薄LEMANIA机芯。柏高尤其重视体育运动，积极参与重大运动赛事，其个性十足的运动表款也深受众多大腕们的喜爱。多年来，柏高坚持独自研发手表机芯，将“最好的腕表将会是下一个”作为座右铭，创造瑞士制表传统与现代技术的结晶，淋漓尽致地诠释了腕表的古典美学。', '瑞士柏高官方旗舰店', '9824', '87571', './images/mysqlimg/paulpicolsign.jpg', './images/mysqlimg/paulpicolcontentimg1.jpg', './images/mysqlimg/paulpicolcontentimg2.jpg', './images/mysqlimg/paulpicolcontentimg3.jpg', './images/mysqlimg/paulpicolcontentimg4.jpg', './images/mysqlimg/paulpicolcontentimg5.jpg', './images/mysqlimg/paulpicolcontentimg6.jpg', './images/mysqlimg/paulpicolcontentimg7.jpg', './images/mysqlimg/paulpicolcontentimg8.jpg', './images/mysqlimg/paulpicolgoods1.jpg', '30,666', '3146', '37760', '瑞士柏高Paul Picot -FIRSHIRE 梦想家系列 全日历月相表 P0459.SG.1232.1604 正装休闲 机械男表（全', './images/mysqlimg/paulpicolgoods2.jpg', '16,740', '1593', '19120', '瑞士柏高Paul Picot YACHTMAN冒险家系列 P1251BJ.SG.4000.2614 机械男表', './images/mysqlimg/paulpicolgoods3.jpg', '21,980', '2080', '24960', '瑞士柏高Paul Picot -FIRSHIRE 梦想家系列  正装商务腕表 P3754.SG.1021.7601 机械男表', './images/mysqlimg/paulpicolgoods4.jpg', '9,999', '1233', '14800', '瑞士柏高Paul Picot -FIRSHIRE 梦想家系列 绅士品格 P3710.SG.1231.7601 5.9mm轻薄正装休闲 机械男表', './images/mysqlimg/paulpicolgoods5.jpg', '27,100', '256', '30800', '瑞士柏高Paul Picot -FIRSHIRE 梦想家系列 P0475.SG.2132.2601 机械男表（英伦造型腕表 ）', './images/mysqlimg/paulpicolgoods6.jpg', '11,780', '1120', '13440', '瑞士柏高Paul Picot -梦想家系列P2061.SG.4000.7601 商务休闲 机械男表', './images/mysqlimg/paulpicolgoods7.jpg', '23,888', '2506', '30080', '瑞士柏高Paul Picot -梦想家系列 轻薄正装商务腕表   P3754D.SG.1131.2621 机械腕表', './images/mysqlimg/paulpicolgoods8.jpg', '15,740', '1500', '18000', '瑞士柏高Paul Picot 创世纪之“海王星”概念腕表 P3755.SG.1131.2601 机械男表');
INSERT INTO `shop` VALUES (10, './images/mysqlimg/muehlelogo.jpg', './images/mysqlimg/muehleimg.jpg', '德国莫勒官方旗舰店', '商务', '运动', '计时', '格拉苏蒂•莫勒（Muehle-Glashuette）是一个拥有150多年历史的德国独立制表品牌。 1869年品牌创始人开始为格拉苏蒂制表业提供精密测量仪器，随后业务扩大至为汽车行业提供精密测量仪器。在品牌悠久的发展历史中，与德国官方的合作从未断绝。', '德国莫勒官方旗舰店', '22092', '39717', './images/mysqlimg/muehlesign.jpg', './images/mysqlimg/muehlecontentimg1.jpg', './images/mysqlimg/muehlecontentimg2.gif', './images/mysqlimg/muehlecontentimg3.jpg', './images/mysqlimg/muehlecontentimg4.jpg', './images/mysqlimg/muehlecontentimg5.jpg', './images/mysqlimg/muehlecontentimg6.jpg', './images/mysqlimg/muehlecontentimg7.jpg', './images/mysqlimg/muehlecontentimg8.jpg', './images/mysqlimg/muehlegoods1.jpg', '9,230', '860', '10330', '【爆款】德国高级独立制表品牌：格拉苏蒂莫勒Muehle·Glashuette-Sporty Instrument Watches 运动系列', './images/mysqlimg/muehlegoods2.jpg', '6,580', '615', '7380', '莫勒Mühle 经典Classical Timepieces M1-40-72-NB机械男表', './images/mysqlimg/muehlegoods3.jpg', '15,200', '1646', '19760', '莫勒·航海领域的专业时计，来自德国格拉苏蒂Muehle·Glashuette Nautical Wristwatches 航海系列 M1-2', './images/mysqlimg/muehlegoods4.jpg', '22,900', '2125', '25500', '【2019年巴塞尔新款】莫勒·航海领域的专业时计，来自德国格拉苏蒂 Muehle·Glashuette-Sporty Ins', './images/mysqlimg/muehlegoods5.jpg', '6,580', '615', '7380', '【2019年巴塞尔新款】莫勒·航海领域的专业时计，来自德国格拉苏蒂 Muehle·Glashuette-Classical ', './images/mysqlimg/muehlegoods6.jpg', '9,590', '799', '9590', '【爆款】德国高级独立制表品牌：格拉苏蒂 莫勒Muehle·Glashuette-Sporty  运动系列 M1-40-14/1-NB  ', './images/mysqlimg/muehlegoods7.jpg', '10,330', '860', '10330', '【爆款】德国高级独立制表品牌：格拉苏蒂Muehle·Glashuette-Sporty  运动系列 M1-37-47-MB 机械男', './images/mysqlimg/muehlegoods8.jpg', '12,950', '1079', '12950', '莫勒·航海领域的专业时计，来自德国格拉苏蒂 Muehle·Glashuette-M1-43-16-LB 单历款机械表');
INSERT INTO `shop` VALUES (11, './images/mysqlimg/IWClogo.jpg', './images/mysqlimg/IWCimg.jpg', '万国IWC', '人群划分', '功能选择', '系列精选', '沙夫豪森万国表IWC 的制表厂设于瑞士东北部沙夫豪森，拥有毋庸置疑的专业制表技术，是生产计时钟表的鼻祖：闻名于世、配备万年历的「达文西腕表系列」是源出于此的计时腕表先驱之一。当然还有首枚「超卓复杂型腕表系列」、超级防磁的「工程师腕表系列」、无惧2000 米水深压力和配备机械水深测量仪的潜水表、专业的IWC 万国表代表作「飞行员腕表系列」，以及同样无可比拟、于1868 年IWC 万国表创立时已经面世的怀表。', '万国IWC', '4022', '23284', './images/mysqlimg/IWCsign.jpg', './images/mysqlimg/IWCcontentimg1.jpg', './images/mysqlimg/IWCcontentimg2.jpg', './images/mysqlimg/IWCcontentimg3.jpg', './images/mysqlimg/IWCcontentimg4.jpg', './images/mysqlimg/IWCcontentimg5.jpg', './images/mysqlimg/IWCcontentimg6.jpg', './images/mysqlimg/IWCcontentimg7.jpg', './images/mysqlimg/IWCcontentimg8.jpg', './images/mysqlimg/IWCgoods1.jpg', '48,400', '4033', '48400', '万国IWC-葡萄牙计时码表 IW371447 机械男表', './images/mysqlimg/IWCgoods2.jpg', '95,500', '8425', '101100', '万国IWC-葡萄牙系列 IW371480 机械男表', './images/mysqlimg/IWCgoods3.jpg', '13,1700', '10975', '131700', '万国IWC-葡萄牙系列 IW503501 男士自动机械表', './images/mysqlimg/IWCgoods4.jpg', '15,3800', '12816', '153800', '万国IWC-葡萄牙系列 IW500106 机械男表', './images/mysqlimg/IWCgoods5.jpg', '35,900', '2991', '35900', '万国IWC-飞行员系列 IW377714 男士自动机械表（万国小王子特别版）', './images/mysqlimg/IWCgoods6.jpg', '41,730', '3669', '44030', '万国IWC-飞行员系列 IW377710 男士自动机械表', './images/mysqlimg/IWCgoods7.jpg', '89,200', '7433', '89200', '[2017限量新款】万国-飞行员系列 IW501004 机械男表', './images/mysqlimg/IWCgoods8.jpg', '214,200', '17850', '214200', '[2017限量新款】万国-飞行员系列 IW502706 机械表');
INSERT INTO `shop` VALUES (12, './images/mysqlimg/TITONIlogo.jpg', './images/mysqlimg/TITONIimg.jpg', '梅花旗舰店', '男女表', '男款', '女款', '自1919年成立以来，梅花Titoni表厂就专注于生产自动机械表，是现今极少有的独立家族制表企业之一。', '梅花旗舰店', '12554', '1827', './images/mysqlimg/TITONIsign.jpg', './images/mysqlimg/TITONIcontentimg1.jpg', './images/mysqlimg/TITONIcontentimg2.jpg', './images/mysqlimg/TITONIcontentimg3.jpg', './images/mysqlimg/TITONIcontentimg4.jpg', './images/mysqlimg/TITONIcontentimg5.jpg', './images/mysqlimg/TITONIcontentimg6.jpg', './images/mysqlimg/TITONIcontentimg7.jpg', './images/mysqlimg/TITONIcontentimg8.jpg', './images/mysqlimg/TITONIgoods1.jpg', '8,692', '724', '8692', '梅花Titoni-Impetus推进系列 83730 SY-271 机械男表', './images/mysqlimg/TITONIgoods2.jpg', '8,113', '710', '8528', '梅花Titoni-Space Star星空系列 83738 SY-363 机械男表', './images/mysqlimg/TITONIgoods3.jpg', '6,220', '546', '6560', '梅花Titoni-Air Master空霸系列 83909 S-354 机械男表', './images/mysqlimg/TITONIgoods4.jpg', '12,227', '10', '12792', '梅花Titoni-Master Series大师系列 83788 S-ST-314  男士自动机械表', './images/mysqlimg/TITONIgoods5.jpg', '6,779', '594', '7134', '梅花TITONI-Space Star系列  83538 S-ST-580 自动机芯ETA2824-2男表', './images/mysqlimg/TITONIgoods6.jpg', '2,352', '211', '2542', '梅花Titoni-Slenderline纤薄系列 TQ 42918 S-ST-584 女士石英表', './images/mysqlimg/TITONIgoods7.jpg', '7,636', '669', '8036', '梅花Titoni-Cosmo King宇宙系列 797 SY-019 男士自动机械表', './images/mysqlimg/TITONIgoods8.jpg', '4,264', '355', '4264', '梅花TITONI-MADEMOISELLE BY TITONI系列 TQ 42912 SRG-590 石英女表');
INSERT INTO `shop` VALUES (13, './images/mysqlimg/TISSOTlogo.jpg', './images/mysqlimg/TISSOTimg.jpg', '天梭TISSOT', '特价专区', '男表', '女表', '从1853年至今，天梭tissot一直致力于开发能为顾客带来惊喜的创新产品。锐意进取、不懈创新的精神使天梭走出瑞士侏罗山区的小镇力洛克，足迹遍布全球150多个国家。从1853年制作带有两个时区的怀表，到采用创新触控技术的T-TOUCH系列腕表，天梭在技术、材料和设计方面已经创造了诸多\"\"，并制造了首枚岩石、木制和珍珠贝母腕表。', '天梭TISSOT', '154887', '84690', './images/mysqlimg/TISSOTsign.jpg', './images/mysqlimg/TISSOTcontentimg1.jpg', './images/mysqlimg/TISSOTcontentimg2.jpg', './images/mysqlimg/TISSOTcontentimg3.jpg', './images/mysqlimg/TISSOTcontentimg4.jpg', './images/mysqlimg/TISSOTcontentimg5.jpg', './images/mysqlimg/TISSOTcontentimg6.jpg', './images/mysqlimg/TISSOTcontentimg7.jpg', './images/mysqlimg/TISSOTcontentimg8.jpg', './images/mysqlimg/TISSOTgoods1.jpg', '3,540', '325', '3910', '【天梭原装正品，全球联保两年】天梭TISSOT-力洛克系列T006.407.11.033.00 自动机械男表', './images/mysqlimg/TISSOTgoods2.jpg', '3,412', '315', '3782', '【天梭原装正品，全球联保两年】天梭TISSOT-力洛克系列 T41.1.183.33 机械女表', './images/mysqlimg/TISSOTgoods3.jpg', '3,540', '325', '3910', '【天梭原装正品，全球联保两年】 天梭TISSOT-力洛克系列 T006.407.11.053.00 机械男表', './images/mysqlimg/TISSOTgoods4.jpg', '3,150', '297', '3570', '【天梭原装正品，全球联保两年】天梭TISSOT-力洛克系列 T006.407.16.033.00 自动机械男表', './images/mysqlimg/TISSOTgoods5.jpg', '1,699', '177', '2125', '天梭TISSOT-弗拉明戈系列 T094.210.11.111.00 石英女表', './images/mysqlimg/TISSOTgoods6.jpg', '4,530', '428', '5142', '天梭TISSOT-杜鲁尔系列 T099.407.11.048.00 黄晓明同款自动机械男表', './images/mysqlimg/TISSOTgoods7.jpg', '7,020', '640', '7690', '天梭TISSOT-力洛克系列 T006.407.11.033.00 、T41.1.183.33 情侣机械表', './images/mysqlimg/TISSOTgoods8.jpg', '1,917', '180', '2167', '[天梭原装正品，全球联保两年]天梭TISSOT-俊雅系列 T063.610.11.037.00 石英男表');
INSERT INTO `shop` VALUES (14, './images/mysqlimg/Ferragamologo.jpg', './images/mysqlimg/Ferragamoimg.jpg', '意大利菲拉格慕官方旗舰店', '系列', '人群', '价格', '萨尔瓦托勒 菲拉格慕（Salvatore Ferragamo）是世界著名的意大利制造奢华品牌之一。品牌保持尊贵的地位以及声誉，并不断扩大，风格华贵典雅，实用性和款式并重，以传统手工设计和款式新颖誉满全球。成为具有特色的时尚奢侈品牌。', '意大利菲拉格慕官方旗舰店', '2232', '4742', './images/mysqlimg/Ferragamosign.jpg', './images/mysqlimg/Ferragamocontentimg1.jpg', './images/mysqlimg/Ferragamocontentimg2.jpg', './images/mysqlimg/Ferragamocontentimg3.jpg', './images/mysqlimg/Ferragamocontentimg4.jpg', './images/mysqlimg/Ferragamocontentimg5.jpg', './images/mysqlimg/Ferragamocontentimg6.jpg', './images/mysqlimg/Ferragamocontentimg7.jpg', './images/mysqlimg/Ferragamocontentimg8.jpg', './images/mysqlimg/Ferragamogoods1.jpg', '6,320', '526', '6320', '【意大利菲拉格慕官方指定平台】 菲拉格慕FIORE TANK系列 SFDN00218 石英女表', './images/mysqlimg/Ferragamogoods2.jpg', '6,320', '526', '6320', '【意大利菲拉格慕官方指定平台】 菲拉格慕FIORE TANK系列 SFDN00118 石英女表', './images/mysqlimg/Ferragamogoods3.jpg', '4,240', '353', '4240', '【意大利菲拉格慕官方指定平台】 菲拉格慕 Ferragamo-Ferragamo casual 系列 SFDC003 18 石英女表', './images/mysqlimg/Ferragamogoods4.jpg', '4,240', '353', '4240', '【意大利菲拉格慕官方指定平台】 菲拉格慕 FERRAGAMO -Fiore系列 SFCS001 18 石英女表', './images/mysqlimg/Ferragamogoods5.jpg', '7,520', '626', '7520', '【意大利菲拉格慕官方指定平台】 菲拉格慕-Ferragamo-Ferragmo1898-FAZ01 0016-智能男表', './images/mysqlimg/Ferragamogoods6.jpg', '7,520', '626', '7520', '【意大利高奢品牌 】 菲拉格慕 F-80Motion 运动系列 FAZ04 0017 智能石英男表', './images/mysqlimg/Ferragamogoods7.jpg', '5,445', '453', '5445', '【意大利菲拉格慕官方指定平台】 菲拉格慕F-80Motion运动系列 FIF03 0015 石英男表', './images/mysqlimg/Ferragamogoods8.jpg', '6,320', '526', '6320', '【意大利菲拉格慕官方指定平台】 菲拉格慕FIORE TANK系列 SFDN00118 石英女表');
INSERT INTO `shop` VALUES (15, './images/mysqlimg/CASIOlogo.jpg', './images/mysqlimg/CASIOimg.jpg', '卡西欧CASIO', '潮男酷女', '价位区间', '表盘大小', '卡西欧手表多年来以真正多功能的G-SHOCK手表著称于世。卡西欧手表所代表的活力、年轻、时尚、多功能的品牌形象已深入民心。卡西欧公司一向以技术胜于同行为己任，历年都会有技术的突破。', '卡西欧CASIO', '47608', '15498', './images/mysqlimg/CASIOsign.jpg', './images/mysqlimg/CASIOcontentimg1.jpg', './images/mysqlimg/CASIOcontentimg2.jpg', './images/mysqlimg/CASIOcontentimg3.jpg', './images/mysqlimg/CASIOcontentimg4.jpg', './images/mysqlimg/CASIOcontentimg5.jpg', './images/mysqlimg/CASIOcontentimg6.jpg', './images/mysqlimg/CASIOcontentimg7.jpg', './images/mysqlimg/CASIOcontentimg8.jpg', './images/mysqlimg/CASIOgoods1.jpg', '286', '24', '286', '卡西欧CASIO-时尚系列 MTP-1303D-1AVDF 石英男表', './images/mysqlimg/CASIOgoods2.jpg', '952', '80', '952', '卡西欧G-SHOCK系列 GA-100CF-1A9PR 时尚街头手表户外运动男表', './images/mysqlimg/CASIOgoods3.jpg', '380', '32', '380', '卡西欧CASIO-时尚系列 MTP-1375L-1AVDF 石英男表', './images/mysqlimg/CASIOgoods4.jpg', '1,030', '85', '1030', '卡西欧 BABY-G系列 黑金街头酷美 BA-110-1APR 户外防水女表', './images/mysqlimg/CASIOgoods5.jpg', '632', '52', '632', '卡西欧CASIO-G-SHOCK-EDIFICE系列 EFV-540L-1AVUPR 石英男表', './images/mysqlimg/CASIOgoods6.jpg', '1,190', '99', '1190', '卡西欧CASIO-Edifice系列 EFR-303D-1AVUPR 男士石英表', './images/mysqlimg/CASIOgoods7.jpg', '478', '40', '478', '卡西欧CASIO-时尚系列 MTP-1375D-1AVDF 石英男表', './images/mysqlimg/CASIOgoods8.jpg', '960', '86', '1032', '卡西欧CASIO-Edifice系列 EFR-304BL-1AVUPF 男士石英表');
INSERT INTO `shop` VALUES (16, './images/mysqlimg/JUNGHANSlogo.jpg', './images/mysqlimg/JUNGHANSimg.jpg', '德国荣汉斯官方旗舰店', '男表', '女表', '情侣表', '荣汉斯（JUNGHANS）钟表品牌诞生于1861年(旧称荣瀚宝星)，由Erhard Junghans兄弟在联邦德国南部的施岚贝格小镇创立。如今有150多年历史的荣汉斯目前德国销量排行前列，拥有德国的钟表工厂，是1972年慕尼黑奥运会指定计时表。同时荣汉斯也是全世界钟表高科技其中者，钟表生产的专利达到3000多项。荣汉斯 的品牌理念“成功源于创新，勇气是成功的关键”。荣汉斯品牌系列众多，包括 max bill系列，大师系列，ERHARD JUNGHANS、PERFORMANCE 四大系列。其中max bill系列和大师系列是其经典。荣汉斯德国表的风格继承了他们影响全世界的建筑风格包豪斯的简洁、形式及功能，因此，荣汉斯 着重的不是表壳的雕刻，机芯的夹板装饰也没有如瑞士表的花多眼乱。所以，荣汉斯 的腕表应可界定为坚守民族特性，整体设计干净简练，处处流露出独有低调奢华的风格工艺。', '德国荣汉斯官方旗舰店', '4509', '4741', './images/mysqlimg/JUNGHANSsign.jpg', './images/mysqlimg/JUNGHANScontentimg1.jpg', './images/mysqlimg/JUNGHANScontentimg2.jpg', './images/mysqlimg/JUNGHANScontentimg3.jpg', './images/mysqlimg/JUNGHANScontentimg4.jpg', './images/mysqlimg/JUNGHANScontentimg5.jpg', './images/mysqlimg/JUNGHANScontentimg6.jpg', './images/mysqlimg/JUNGHANScontentimg7.jpg', './images/mysqlimg/JUNGHANScontentimg8.jpg', './images/mysqlimg/JUNGHANSgoods1.jpg', '7,450', '695', '8350', '荣汉斯JUNGHANS-max bill 系列 027/4700.04 自动机械表', './images/mysqlimg/JUNGHANSgoods2.jpg', '4,690', '440', '5290', '荣汉斯JUNGHANS-max bill 系列 041/4461.04 中性石英表', './images/mysqlimg/JUNGHANSgoods3.jpg', '5,920', '493', '5920', '荣汉斯JUNGHANS-max bill 系列 027/3701.04 机械女表', './images/mysqlimg/JUNGHANSgoods4.jpg', '18,420', '1710', '20520', '荣汉斯JUNGHANS-大师系列 027/7203.01 机械男表', './images/mysqlimg/JUNGHANSgoods5.jpg', '7,180', '673', '8080', '荣汉斯JUNGHANS-max bill 系列 027/3502.00 机械表', './images/mysqlimg/JUNGHANSgoods6.jpg', '5,920', '493', '5920', '荣汉斯JUNGHANS-max bill 系列 027/3701.00机械女表（新型号027/3701.04）', './images/mysqlimg/JUNGHANSgoods7.jpg', '11,520', '960', '11520', '荣汉斯JUNGHANS-大师系列 027/3503.01 机械男表', './images/mysqlimg/JUNGHANSgoods8.jpg', '15,220', '1410', '16920', '荣汉斯JUNGHANS-大师系列 027/7333.00 机械男表');
INSERT INTO `shop` VALUES (17, './images/mysqlimg/constantlogo.jpg', './images/mysqlimg/constantimg.jpg', '瑞士康斯登官方旗舰店', '风格', '适用人群', '商品属性', '19世纪中期， Stas斯达家族-康斯登·斯达（Constant Stas） 创立Lithography，为当时快速成长的Friesche KlokkenIndusttry生产表盘。为了纪念曾祖辈与钟表界的宿缘，1988年，家族第四代传人彼得·斯达（Peter Stas）将品牌林福古菲（Lithography）更名为', '瑞士康斯登官方旗舰店', '9084', '6680', './images/mysqlimg/constantsign.jpg', './images/mysqlimg/constantcontentimg1.jpg', './images/mysqlimg/constantcontentimg2.jpg', './images/mysqlimg/constantcontentimg3.jpg', './images/mysqlimg/constantcontentimg4.jpg', './images/mysqlimg/constantcontentimg5.jpg', './images/mysqlimg/constantcontentimg6.jpg', './images/mysqlimg/constantcontentimg7.jpg', './images/mysqlimg/constantcontentimg8.jpg', './images/mysqlimg/constantgoods1.jpg', '6,440', '615', '7380', '康斯登Frederique Constant 百年典雅系列 天悦 FC-200M1ER32B  超薄石英女表', './images/mysqlimg/constantgoods2.jpg', '6,450', '665', '7990', '康斯登Frederique Constant 百年典雅系列  FC-303MC4P6 儒雅商务机械男表', './images/mysqlimg/constantgoods3.jpg', '6,798', '676', '8118', '康斯登Frederique Constant -百年典雅系列 焯见智慧 FC-303C5B4 自动机械男表', './images/mysqlimg/constantgoods4.jpg', '5,720', '546', '6560', '康斯登Frederique Constant 百年典雅系列 FC-303S5B6  自动机械男表', './images/mysqlimg/constantgoods5.jpg', '6,660', '635', '7620', '康斯登Frederique Constant  百年典雅系列 天鹅湖 FC-200MPW2V6B 超薄正装 石英女表', './images/mysqlimg/constantgoods6.jpg', '7,610', '744', '8930', '瑞士康斯登 Frederique Constant 百年典雅系列 天方自动 FC-310MC4S36 机械男表', './images/mysqlimg/constantgoods7.jpg', '5,740', '546', '6560', '瑞士康斯登 Frederique Constant 百年典雅系列 自动 FC-303MS5B6 机械男表', './images/mysqlimg/constantgoods8.jpg', '13,670', '1359', '16310', '康斯登Frederique Constant 超薄系列 FC-312V4S4 自动机械男表');
INSERT INTO `shop` VALUES (18, './images/mysqlimg/HAMILTONlogo.jpg', './images/mysqlimg/HAMILTONimg.jpg', '汉米尔顿HAMILTON', '男士专区', '女士专区', '功能分类', '　　Hamilton于1892年成立于美国宾夕法尼亚州兰开斯特市(Lancaster)，是Swatch集团的成员，以创新的设计和钟表技术闻名于世，更因与好莱坞的深厚渊源而声名远播，至今已在超过300多部的好莱坞高级影片中频频亮相。', '汉米尔顿HAMILTON', '45141', '46134', './images/mysqlimg/HAMILTONsign.jpg', './images/mysqlimg/HAMILTONcontentimg1.jpg', './images/mysqlimg/HAMILTONcontentimg2.jpg', './images/mysqlimg/HAMILTONcontentimg3.jpg', './images/mysqlimg/HAMILTONcontentimg4.jpg', './images/mysqlimg/HAMILTONcontentimg5.jpg', './images/mysqlimg/HAMILTONcontentimg6.jpg', './images/mysqlimg/HAMILTONcontentimg7.jpg', './images/mysqlimg/HAMILTONcontentimg8.jpg', './images/mysqlimg/HAMILTONgoods1.jpg', '2,750', '245', '2950', '汉米尔顿Hamilton-美国经典系列 H11421514 石英女表', './images/mysqlimg/HAMILTONgoods2.jpg', '6,700', '608', '7300', '汉米尔顿Hamilton-爵士系列 H32405811 机械女表', './images/mysqlimg/HAMILTONgoods3.jpg', '6,950', '629', '7550', '汉米尔顿Hamilton-美国经典-铁路系列H40405191  机械女表', './images/mysqlimg/HAMILTONgoods4.jpg', '11,000', '926', '11000', '汉米尔顿Hamilton-美国经典-铁路系列 H40391191  石英女表', './images/mysqlimg/HAMILTONgoods5.jpg', '5,400', '491', '5900', '汉米尔顿Hamilton-爵士系列  开心 H32565555 机械男表', './images/mysqlimg/HAMILTONgoods6.jpg', '5,000', '450', '5400', '汉米尔顿Hamilton-爵士系列 双历 H32505151 机械男表', './images/mysqlimg/HAMILTONgoods7.jpg', '7,100', '641', '7700', '汉米尔顿Hamilton-爵士系列 H32735551 自动机械男表', './images/mysqlimg/HAMILTONgoods8.jpg', '6,000', '541', '6500', '汉米尔顿Hamilton-美国经典系列 臻薄 H38735751 机械男表');
INSERT INTO `shop` VALUES (19, './images/mysqlimg/CENTURYlogo.jpg', './images/mysqlimg/CENTURYimg.jpg', '瑞士世纪官方旗舰店', '时尚', '休闲', '典雅', '世纪表由Hans Ulrich Klingenberg创立于1929年的瑞士Biel，这是瑞士制表业的心脏地带，CENTURY品牌，以大胆 新颖的手法，设计并制造出多款历久弥新、完美无瑕的钟表珠宝而闻名。其创始人Hans Ulrich Klingenberg，更通过研 制出抗磨损蓝宝石表壳及蓝宝石水晶表面，全球首创的蓝宝石腕表，时至今日仍是炙手可热的名表之一。', '瑞士世纪官方旗舰店', '1584', '2905', './images/mysqlimg/CENTURYsign.jpg', './images/mysqlimg/CENTURYcontentimg1.jpg', './images/mysqlimg/CENTURYcontentimg2.jpg', './images/mysqlimg/CENTURYcontentimg3.jpg', './images/mysqlimg/CENTURYcontentimg4.jpg', './images/mysqlimg/CENTURYcontentimg5.jpg', './images/mysqlimg/CENTURYcontentimg6.jpg', './images/mysqlimg/CENTURYcontentimg7.jpg', './images/mysqlimg/CENTURYcontentimg8.jpg', './images/mysqlimg/CENTURYgoods1.jpg', '20,880', '1740', '20880', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-AFFINITY系列-腕间精灵 632.7.S.12.16.SK 石英女', './images/mysqlimg/CENTURYgoods2.jpg', '19,360', '1613', '19360', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-AFFINITY系列-微蓝色调 632.7.S.22.16.CXO 石英', './images/mysqlimg/CENTURYgoods3.jpg', '33,040', '2753', '33040', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-AFFINITY系列-高贵典雅  632.7.Q.12.16.SK机械女', './images/mysqlimg/CENTURYgoods4.jpg', '31,440', '2620', '31440', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-AFFINITY系列-低调的奢华 632.7.Q.22.16.CXO 机', './images/mysqlimg/CENTURYgoods5.jpg', '20,880', '1740', '20880', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-AFFINITY系列-温润曼妙 632.7.S.22.16.SK 石英女', './images/mysqlimg/CENTURYgoods6.jpg', '32,240', '2686', '32240', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-ELEGANCE系列-都市孤岛 648.7.N.S1.12.15D.CXM 机', './images/mysqlimg/CENTURYgoods7.jpg', '33,760', '2813', '33760', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-ELEGANCE系列-机械之芯 648.7.N.S1.12.SF 机械男', './images/mysqlimg/CENTURYgoods8.jpg', '31,440', '2620', '31440', '世纪独家蓝宝石 瑞士高端珠宝腕表：Century世纪表-AFFINITY系列- 632.7.Q.72.16.CEK 自动机械女表');
INSERT INTO `shop` VALUES (20, './images/mysqlimg/cartierlogo.jpg', './images/mysqlimg/cartierimg.jpg', '卡地亚CARTIER', '场景搭配', '男表专区', '系列分类', '　　卡地亚(Cartier SA)是一间法国钟表及珠宝制造商，于1847年由Louis-Fran?ois Cartier在巴黎Rue Montorgueil 31号创办。1874年，其子亚法·卡地亚继承其管理权，由其孙子路易·卡地亚、皮尔·卡地亚与积斯·卡地亚将其发展成世界著名品牌。现为瑞士历峰集团(Compagnie Financière Richemont SA)下属公司。1904年曾为飞机师阿尔拔图·山度士·度门设计世界上首只戴在手腕的腕表——卡地亚山度士腕表(Cartier Santos)。', '卡地亚CARTIER', '4307', '6926', './images/mysqlimg/cartiersign.jpg', './images/mysqlimg/cartiercontentimg1.jpg', './images/mysqlimg/cartiercontentimg2.jpg', './images/mysqlimg/cartiercontentimg3.jpg', './images/mysqlimg/cartiercontentimg4.jpg', './images/mysqlimg/cartiercontentimg5.jpg', './images/mysqlimg/cartiercontentimg6.jpg', './images/mysqlimg/cartiercontentimg7.jpg', './images/mysqlimg/cartiercontentimg8.jpg', './images/mysqlimg/cartiergoods1.jpg', '30,600', '2683', '32200', '卡地亚Cartier-蓝气球系列 W69010Z4（小号） 女士石英表', './images/mysqlimg/cartiergoods2.jpg', '34,920', '3043', '36520', '卡地亚Cartier-蓝气球系列 W6920085 机械女表', './images/mysqlimg/cartiergoods3.jpg', '23,990', '1999', '23990', '卡地亚cartier-RONDE SOLO DE CARTIER系列 W6701011 机械男表', './images/mysqlimg/cartiergoods4.jpg', '52,440', '4370', '52440', '卡地亚cartier-TANK系列 W5310036 石英女表', './images/mysqlimg/cartiergoods5.jpg', '43,160', '3771', '45260', '卡地亚Cartier-蓝气球系列 W69012Z4（大号） 机械男表', './images/mysqlimg/cartiergoods6.jpg', '18,446', '1587', '19046', '卡地亚cartier-TANK SOLO系列 W5200014 女士石英表', './images/mysqlimg/cartiergoods7.jpg', '38,236', '3319', '39836', '卡地亚Cartier-BALLON BLEU DE蓝气球系列 W6920071 机械女表', './images/mysqlimg/cartiergoods8.jpg', '16,788', '1449', '17388', '卡地亚cartier-TANK SOLO系列 WSTA0028 中性石英表');
INSERT INTO `shop` VALUES (21, './images/mysqlimg/SEIKOlogo.jpg', './images/mysqlimg/SEIKOimg.jpg', '精工官方旗舰店', 'Prospex 系列', 'Presage 系列', 'Premier 系列', '精工（SEIKO）是一家著名的日本制表公司，始创于1881年，公司原名为服部计时店，1892年改名为精工舍。1924年，发表了首只正式 使用精工品牌的手表。1969年，精工表推出了世界上首款指针式石英手表-SEIKO ASTRON35SQ。1995年，精工舍与日本东方表公司共同 创建了一间合资工厂。精工舍还是电脑打印机制造商-爱普生（EPSON）的母公司。', '精工官方旗舰店', '17832', '9856', './images/mysqlimg/SEIKOsign.jpg', './images/mysqlimg/SEIKOcontentimg1.jpg', './images/mysqlimg/SEIKOcontentimg2.jpg', './images/mysqlimg/SEIKOcontentimg3.jpg', './images/mysqlimg/SEIKOcontentimg4.jpg', './images/mysqlimg/SEIKOcontentimg5.jpg', './images/mysqlimg/SEIKOcontentimg6.jpg', './images/mysqlimg/SEIKOcontentimg7.jpg', './images/mysqlimg/SEIKOcontentimg8.jpg', './images/mysqlimg/SEIKOgoods1.jpg', '1,700', '141', '1700', '精工SEIKO-Seiko 5系列 SRP601J1 自动机械男表', './images/mysqlimg/SEIKOgoods2.jpg', '1,162', '96', '1162', '精工SEIKO-Seiko 5系列 SYMH17J1  机械女表', './images/mysqlimg/SEIKOgoods3.jpg', '2,655', '221', '2655', '精工SEIKO-Presage 鸡尾酒系列 Bluemoon SRPB41J1 自动机械男表', './images/mysqlimg/SEIKOgoods4.jpg', '1,050', '87', '1050', '精工SEIKO-Seiko 5系列 SYMK19J1 自动机械女表', './images/mysqlimg/SEIKOgoods5.jpg', '3,240', '270', '3240', '精工SEIKO-Prospex系列 SRPA21J1 机械男表 ', './images/mysqlimg/SEIKOgoods6.jpg', '3,060', '255', '3060', '精工SEIKO-Presage 鸡尾酒系列 Margarita SRPB44J1 自动机械男表', './images/mysqlimg/SEIKOgoods7.jpg', '899', '74', '899', '精工SEIKO-Seiko 5系列 SYMK17J1 自动机械女表', './images/mysqlimg/SEIKOgoods8.jpg', '9,00', '75', '900', '精工SEIKO-Seiko 5系列 SNKE57J1 自动机械男表');
INSERT INTO `shop` VALUES (22, './images/mysqlimg/HEUERlogo.jpg', './images/mysqlimg/HEUERimg.jpg', '泰格豪雅TAG HEUER', '男表', '女表', '机械表', '　　自1860年以来，泰格豪雅始终是瑞士知名前卫腕表和计时码表的典范，也是发展最迅速的瑞士腕表品牌之一。这个瑞士制表业的传奇从运动中汲取积极承诺，创造出了有史以来最准确的计时仪器和由运动激发灵感的计时器。目前，泰格豪雅是一家能够精准到十分之一、百分之一、和千分之一的腕表品牌。从20世纪20年代的奥林匹克运动会，到凭借精准到万分之一秒的卓越技术成为传奇印迪500赛车官方计时器的全新角色，泰格豪雅不断追求创新、卓越、表现和声望，不断攀登更高的目标。 这个品牌与2008年F1世界冠军、沃达丰-迈凯轮车队车手刘易斯﹒汉密尔顿(Lewis Hamilton)长达六年的合作便可证明这些，泰格豪雅与迈凯轮车队长达25年的密切合作、 以及与其车手刘易斯与海基﹒科瓦莱宁(Heikki Kovalainen)的代言都不断地证明着品牌的追求和理念。豪雅更通过与2007年F1世界冠军、法拉利车队F1车手基米﹒莱科宁(Kimi R?ikk?nen)，全球排名的高尔夫球手老虎伍兹(Tiger Woods)、WTA网球冠军玛利亚﹒莎拉波娃(Maria Sharapova)、Nascar偶像杰夫﹒乔登(Jeff Gordon)、F1车手兼眼镜系列代言人塞巴斯蒂安﹒布戴(Sébastien Bourdais)、F1车手塞巴斯蒂安﹒瓦特尔(Sebastian Vettel)、以及好莱坞标志性人物莱昂那多·迪卡普里奥 (Leonardo DiCaprio)和宝莱坞明星沙鲁克﹒罕(Shah Rukh Khan)等人的携手合作，成为凝聚魅力和品质的标志. 泰格豪雅是瑞士制表业俱乐部FHH(高级钟表基金会)的特权会员。', '泰格豪雅TAG HEUER', '7064', '1567', './images/mysqlimg/HEUERsign.jpg', './images/mysqlimg/HEUERcontentimg1.jpg', './images/mysqlimg/HEUERcontentimg2.jpg', './images/mysqlimg/HEUERcontentimg3.jpg', './images/mysqlimg/HEUERcontentimg4.jpg', './images/mysqlimg/HEUERcontentimg5.jpg', './images/mysqlimg/HEUERcontentimg6.jpg', './images/mysqlimg/HEUERcontentimg7.jpg', './images/mysqlimg/HEUERcontentimg8.jpg', './images/mysqlimg/HEUERgoods1.jpg', '16,868', '1530', '18368', '泰格豪雅(TAG HEUER)-卡莱拉CARRERA系列  WAR2414.BA0776 自动机械女表', './images/mysqlimg/HEUERgoods2.jpg', '10,380', '956', '11480', '泰格豪雅(TAG HEUER)-FORMULA 1系列 WBJ1317.FC8230 女士石英表', './images/mysqlimg/HEUERgoods3.jpg', '5,582', '519', '6232', '【闪购特惠】泰格豪雅(TAG HEUER)- F1 一级方程式系列 WBJ1312.FC8231 女士石英表', './images/mysqlimg/HEUERgoods4.jpg', '12,464', '1038', '12464', '泰格豪雅(TAG HEUER)- F1 一级方程式系列 WBJ1416.BA0664 女士石英表', './images/mysqlimg/HEUERgoods5.jpg', '7,134', '594', '7134', '泰格豪雅(TAG HEUER)- F1 一级方程式系列 WBJ1412.BA0664 女士石英表', './images/mysqlimg/HEUERgoods6.jpg', '15,908', '1325', '15908', '泰格豪雅(TAG HEUER)-卡莱拉CARRERA系列 WBK2311.FC8258 自动机械女表', './images/mysqlimg/HEUERgoods7.jpg', '22,500', '2050', '24600', '泰格豪雅(TAG HEUER)-卡莱拉CARRERA系列 WBK1316.BA0652 女士石英表', './images/mysqlimg/HEUERgoods8.jpg', '9,922', '826', '9922', '泰格豪雅(TAG HEUER)-林肯LINK系列 WBC1311.BA0600 石英女表');
INSERT INTO `shop` VALUES (23, './images/mysqlimg/CIIZENlogo.jpg', './images/mysqlimg/CIIZENimg.jpg', '西铁城官方旗舰店', '场景搭配', '男表专区', '功能分类', '西铁城公司的前身为日本尚工舍时计研究所，创立于1918年，主要从事钟表的开发和制造，在1924年制造出了只怀表。西铁城时计株式会社成立于1930年5月，由当时的东京市市长命名为“CITIZEN”，意思是全世界全体公民。', '西铁城官方旗舰店', '44576', '24519', './images/mysqlimg/CIIZENsign.jpg', './images/mysqlimg/CIIZENcontentimg1.jpg', './images/mysqlimg/CIIZENcontentimg2.jpg', './images/mysqlimg/CIIZENcontentimg3.jpg', './images/mysqlimg/CIIZENcontentimg4.jpg', './images/mysqlimg/CIIZENcontentimg5.jpg', './images/mysqlimg/CIIZENcontentimg6.jpg', './images/mysqlimg/CIIZENcontentimg7.jpg', './images/mysqlimg/CIIZENcontentimg8.jpg', './images/mysqlimg/CIIZENgoods1.jpg', '1,510', '140', '1690', '西铁城Citizen-光动能男表系列 AW0077-19LB 光动能男表', './images/mysqlimg/CIIZENgoods2.jpg', '1,600', '148', '1780', '西铁城Citizen-光动能男表系列 AW0079-13XB 光动能男表', './images/mysqlimg/CIIZENgoods3.jpg', '2,040', '190', '2280', '西铁城Citizen-光动能女表系列 EM0810-84D 光动能女表 2020新品', './images/mysqlimg/CIIZENgoods4.jpg', '2,650', '245', '2950', '西铁城Citizen-光动能女表系列 FC8000-55D万年历光动能女表 2020新品', './images/mysqlimg/CIIZENgoods5.jpg', '2,488', '232', '2788', '西铁城Citizen-Promaster系列 BX1010-11L 万年历 光动能男表', './images/mysqlimg/CIIZENgoods6.jpg', '1,600', '148', '1780', '西铁城Citizen-光动能男表系列 BM7466-81H 光动能男表', './images/mysqlimg/CIIZENgoods7.jpg', '2,299', '231', '2772', '西铁城Citizen-光动能男表系列 BX1001-11L 万年历男表', './images/mysqlimg/CIIZENgoods8.jpg', '1,300', '118', '1420', '西铁城Citizen-光动能男表系列 BM7460-11E 光动能男表');
INSERT INTO `shop` VALUES (24, './images/mysqlimg/timinglogo.jpg', './images/mysqlimg/timingimg.jpg', '天铭官方旗舰店', '型男专区', '淑女专区', '功能分类', '1982年成立了协诚钟表厂(公司前身)，专注于机械表的设计与製造，随著每年近二百款的新款产品问世，CHARLES深感中国人自创品牌的时机已臻成熟，遂于香港与意大利等多地注册Timing天铭表商标。', '天铭官方旗舰店', '9467', '15735', './images/mysqlimg/timingsign.jpg', './images/mysqlimg/timingcontentimg1.jpg', './images/mysqlimg/timingcontentimg2.jpg', './images/mysqlimg/timingcontentimg3.jpg', './images/mysqlimg/timingcontentimg4.jpg', './images/mysqlimg/timingcontentimg5.jpg', './images/mysqlimg/timingcontentimg6.jpg', './images/mysqlimg/timingcontentimg7.jpg', './images/mysqlimg/timingcontentimg8.jpg', './images/mysqlimg/timinggoods1.jpg', '4,580', '381', '273', '意大利品牌：天铭（Timing）-源动系列 2077SX（玫瑰金壳玫瑰金机芯 ）机械男表', './images/mysqlimg/timinggoods2.jpg', '3,280', '273', '3280', '意大利品牌：天铭（Timing）-特别限量版系列 未羊年纪念款-“吉祥如意” 8212SX 唐瓷机械表', './images/mysqlimg/timinggoods3.jpg', '5,210', '434', '5210', '意大利品牌：天铭（Timing）-源动系列 8081SX-A（玫瑰金色壳白面）机械男表', './images/mysqlimg/timinggoods4.jpg', '5,460', '455', '5460', '意大利品牌：天铭（Timing）-星际迷航系列 8153SX-A（钢色壳墨绿色面）机械男表', './images/mysqlimg/timinggoods5.jpg', '3,299', '323', '3880', '意大利品牌：天铭（Timing）-镂空系列 8130SX（钢壳白盘）镂空机械男表', './images/mysqlimg/timinggoods6.jpg', '5,460', '455', '5460', '意大利品牌：天铭（Timing）-星际迷航系列 8153SX-A（钢色壳蓝色面）机械男表', './images/mysqlimg/timinggoods7.jpg', '6,610', '550', '6610', '意大利品牌：天铭（Timing）-急速系列 8146SX（玫瑰金壳白色表面）自动机械表', './images/mysqlimg/timinggoods8.jpg', '3,280', '273', '3280', '意大利品牌：天铭（Timing）- 特别限量版系列 午马年纪念款-8212SX 马上得福 唐瓷机械表');
INSERT INTO `shop` VALUES (25, './images/mysqlimg/ruishihenglilogo.jpg', './images/mysqlimg/ruishihengliimg.jpg', '瑞士亨利慕时官方旗舰店', '表壳材质', '功能分类', '尺寸规格', '近年来由H.Moser&Cie研制的钟表继承了传统的经典优雅外观配以略显低调的风格，一如既往地采用了质量的传统机械钟表结构。不言而喻，这种集技术创新和高度使用便利性 于一身的杰作，只能在H.Moser&Cie生产的钟表中找到。', '瑞士亨利慕时官方旗舰店', '377', '65848', './images/mysqlimg/ruishihenglisign.jpg', './images/mysqlimg/ruishihenglicontentimg1.jpg', './images/mysqlimg/ruishihenglicontentimg2.jpg', './images/mysqlimg/ruishihenglicontentimg3.jpg', './images/mysqlimg/ruishihenglicontentimg4.jpg', './images/mysqlimg/ruishihenglicontentimg5.jpg', './images/mysqlimg/ruishihenglicontentimg6.jpg', './images/mysqlimg/ruishihenglicontentimg7.jpg', './images/mysqlimg/ruishihenglicontentimg8.jpg', './images/mysqlimg/ruishihengligoods1.jpg', '119,700', '11400', '136800', '瑞士亨利·慕时 H.Moser & Cie ENDEAVOUR CENTRE SECONDS系列 1343-0105 机械男表', './images/mysqlimg/ruishihengligoods2.jpg', '123,100', '11400', '136800', '瑞士亨利·慕时 H.Moser & Cie勇创者系列 1343-0100 机械男表', './images/mysqlimg/ruishihengligoods3.jpg', '102,600', '8550', '102600', '瑞士亨利·慕时 H.Moser & Cie勇创者系列 1343-0204 机械男表', './images/mysqlimg/ruishihengligoods4.jpg', '102400', '8533', '102400', '瑞士亨利·慕时 H.Moser & Cie勇创者系列 321-503-016 机械男表', './images/mysqlimg/ruishihengligoods5.jpg', '136,800', '11400', '136800', '瑞士亨利·慕时 H.Moser & Cie勇创者系列343-505-019 机械男表', './images/mysqlimg/ruishihengligoods6.jpg', '133,380', '11115', '133380', '瑞士亨利·慕时 H.Moser & Cie勇创者系列 1343-0205 机械男表', './images/mysqlimg/ruishihengligoods7.jpg', '115,200', '9600', '115200', '瑞士亨利·慕时 H.Moser & Cie勇创者系列 1321-0210 机械男表', './images/mysqlimg/ruishihengligoods8.jpg', '153,900', '12825', '153900', '瑞士亨利·慕时 H.Moser & Cie勇创者系列 1343-0204 机械男表');
INSERT INTO `shop` VALUES (26, './images/mysqlimg/ARMANDlogo.jpg', './images/mysqlimg/ARMANDimg.jpg', '瑞士艾美达官方旗舰店', '人群划分', '功能选择', '风格搭配', '艾美达（Armand Nicolet），始于1875年，位于侏罗山谷的拉姆朗市，是著名的钟表圣地 ，Nicolet家族成员在这里都以从事钟表生意而闻名。艾美达具有141年悠久历史，是瑞士经典传承的腕表品牌，一直以来专注于机械表的生产，积累了丰富的机械表机芯制造经验。艾美达腕表讲求考究的手工打磨工艺，从表盘、表壳、表带到机芯的工艺流程都苛求完美。与其他品牌相比，艾美达拥有顶级打磨技术水平，在腕表的细节处理上力求精益求精。', '瑞士艾美达官方旗舰店', '16012', '10800', './images/mysqlimg/ARMANDsign.jpg', './images/mysqlimg/ARMANDcontentimg1.jpg', './images/mysqlimg/ARMANDcontentimg2.png', './images/mysqlimg/ARMANDcontentimg3.jpg', './images/mysqlimg/ARMANDcontentimg4.jpg', './images/mysqlimg/ARMANDcontentimg5.jpg', './images/mysqlimg/ARMANDcontentimg6.png', './images/mysqlimg/ARMANDcontentimg7.jpg', './images/mysqlimg/ARMANDcontentimg8.jpg', './images/mysqlimg/ARMANDgoods1.jpg', '6,080', '506', '6080', '瑞士独立制表品牌 艾美达（Armand Nicolet）-当代休闲 AL3系列 A882AAA-AN-P882BC8  石英、镶钻月相', './images/mysqlimg/ARMANDgoods2.jpg', '18,940', '1866', '22400', '瑞士独立制表品牌艾美达（Armand Nicolet）-当代经典M02-4系列 日期计时 A844AAA-BU-M9742 自动机械', './images/mysqlimg/ARMANDgoods3.jpg', '8,580', '853', '10240', '瑞士独立制表品牌艾美达（Armand Nicolet）-当代经典M02-4系列日期显示大三针 A840AAA-AG-M9742 商', './images/mysqlimg/ARMANDgoods4.jpg', '6,999', '853', '10240', '瑞士独立制表品牌艾美达（Armand Nicolet）-当代经典M02-4系列日期显示大三针 A840AAA-NR-M9742 商', './images/mysqlimg/ARMANDgoods5.jpg', '7,540', '746', '8960', '瑞士独立制表品牌艾美达（Armand Nicolet）-当代经典M02-4系列日期显示 A840AAA-NR-P840NR2 自动机', './images/mysqlimg/ARMANDgoods6.jpg', '6,690', '746', '8960', '瑞士独立制表品牌艾美达（Armand Nicolet）-当代经典M02-4系列日期显示大三针 A840AAA-AG-P840MR2 ', './images/mysqlimg/ARMANDgoods7.jpg', '11,940', '1173', '14080', '瑞士独立制表品牌艾美达（Armand Nicolet）-当代经典M02-4系列 GMT两地时 A846AAA-AG-P840MR2 自动机', './images/mysqlimg/ARMANDgoods8.jpg', '18,940', '1866', '22400', '瑞士独立制表品牌艾美达（Armand Nicolet）-当代经典M02-4系列 日期计时 A844AAA-AG-M9742 自动机械');
INSERT INTO `shop` VALUES (27, './images/mysqlimg/AEROWATCHlogo.jpg', './images/mysqlimg/AEROWATCHimg.jpg', '瑞士爱罗官方旗舰店', '人群划分', '功能选择', '风格搭配', '爱罗(AEROWATCH)是一家具有百年历史，家族式经营的独立制表品牌，表厂建立于1910年，现位于在瑞士制表圣地洳山谷(Jura)的勒努瓦尔蒙（Le Noirmont） 。 爱罗在次世界大战中饱受灾难，厂址经历过数次变迁，却依然坚持将瑞士制表传统延续下去。20世纪30年代，爱罗表厂生产的钟表，凭借卓越的制表工艺和先进的技术，受到市场和专业机构的一致好评。1959年，乔治•克雷沃伊谢（Georges Crevoisier）成功的从他父亲马克西姆•克雷沃伊谢（Maxime Crevoisier）手中接过了生意，将爱罗表推广到了30多个国家，并取得了很高的国际声誉。 ', '瑞士爱罗官方旗舰店', '8721', '3198', './images/mysqlimg/AEROWATCHsign.jpg', './images/mysqlimg/AEROWATCHcontentimg1.jpg', './images/mysqlimg/AEROWATCHcontentimg2.jpg', './images/mysqlimg/AEROWATCHcontentimg3.jpg', './images/mysqlimg/AEROWATCHcontentimg4.jpg', './images/mysqlimg/AEROWATCHcontentimg5.jpg', './images/mysqlimg/AEROWATCHcontentimg6.jpg', './images/mysqlimg/AEROWATCHcontentimg7.jpg', './images/mysqlimg/AEROWATCHcontentimg8.jpg', './images/mysqlimg/AEROWATCHgoods1.jpg', '5,160', '480', '5760', '爱罗Aerowatch- Les Grandes Classiques新古典系列 A 83966 AA01 M 石英男表', './images/mysqlimg/AEROWATCHgoods2.jpg', '14,700', '1366', '16400', '爱罗Aerowatch- Les Grandes Classiques商务休闲系列  A 61968 AA04 M  机械男表', './images/mysqlimg/AEROWATCHgoods3.jpg', '3,440', '320', '3840', '爱罗Aerowatch- HERITAGE继承者系列 A 21976 AA02 石英男表', './images/mysqlimg/AEROWATCHgoods4.jpg', '14,700', '1366', '16400', '【店长推荐】爱罗Aerowatch- Les Grandes Classiques 新古典系列 ETA 7750卓越计时 A 61968 AA01 M 飞行员 ', './images/mysqlimg/AEROWATCHgoods5.jpg', '3,900', '366', '4400', '爱罗Aerowatch-Renaissance系列  A 08937 AA01 M 石英男表（已绝版）', './images/mysqlimg/AEROWATCHgoods6.jpg', '1,780', '173', '2080', '爱罗Aerowatch Les Grandes Classiques 商务休闲系列 A 49978 AA02 石英女表', './images/mysqlimg/AEROWATCHgoods7.jpg', '14,080', '1306', '15680', '爱罗Aerowatch- Les Grandes Classiques商务休闲系列  A 61968 AA04  机械男表', './images/mysqlimg/AEROWATCHgoods8.jpg', '2,660', '246', '2960', '爱罗Aerowatch-Les Grandes Classiques系列  A 24962 BI01 男士石英表');

